def evaluate_agent_retrieval(executor, eval_cases: list[dict]) -> dict:
    """
    eval_cases: [{
        "query": str,
        "should_retrieve": bool,
        "gold_chunk_ids": list[str]
    }]
    """
    tool_call_tp = tool_call_fp = tool_call_fn = 0
    chunk_hits = chunk_total = 0

    for case in eval_cases:
        result = executor.invoke({"input": case["query"]})
        steps = result.get("intermediate_steps", [])
        did_retrieve = any(action.tool == "search_product_docs" for action, _ in steps)

        if case["should_retrieve"] and did_retrieve:
            tool_call_tp += 1
        elif case["should_retrieve"] and not did_retrieve:
            tool_call_fn += 1
        elif not case["should_retrieve"] and did_retrieve:
            tool_call_fp += 1

        if did_retrieve and case["gold_chunk_ids"]:
            retrieved_ids = {
                doc.metadata.get("chunk_id")
                for _, obs in steps
                for doc in (obs if isinstance(obs, list) else [])
            }
            chunk_hits += bool(retrieved_ids & set(case["gold_chunk_ids"]))
            chunk_total += 1

    precision = tool_call_tp / (tool_call_tp + tool_call_fp) if (tool_call_tp + tool_call_fp) else 0
    recall = tool_call_tp / (tool_call_tp + tool_call_fn) if (tool_call_tp + tool_call_fn) else 0
    chunk_recall = chunk_hits / chunk_total if chunk_total else 0
    return {"tool_precision": precision, "tool_recall": recall, "chunk_recall": chunk_recall}
